class Solution:
    def removeConsecutiveDuplicates(self, s: str) -> str:
        if not s: return s
        res = []
        for i in range(len(s)):
            if i == 0 or s[i] != s[i-1]: res.append(s[i])
        return ''.join(res)

s = input()
