#include <iostream>
#include <string>

using namespace std;

string removeConsecutiveDuplicates(string s) {
    if(s.empty()) return s;
    string res;
    for(int i=0; i<s.length(); i++) {
        if(i == 0 || s[i] != s[i-1]) res += s[i];
    }
    return res;
}

int main() {
    string s;
    cin >> s;
    cout << removeConsecutiveDuplicates(s) << endl;
    return 0;
}
